mapper.select:
SELECT id, user_id, title, company, location, salary, file_path, create_time, update_time
FROM tb_jd


        AND CAST(id AS CHAR) LIKE CONCAT('%', #{condition.id}, '%')


        AND CAST(user_id AS CHAR) LIKE CONCAT('%', #{condition.userId}, '%')


        AND (
            title LIKE CONCAT('%', #{condition.jdKeyword}, '%')
            OR company LIKE CONCAT('%', #{condition.jdKeyword}, '%')
            OR location LIKE CONCAT('%', #{condition.jdKeyword}, '%')


            OR SUBSTRING_INDEX(
                 SUBSTRING_INDEX(REPLACE(file_path, '\\', '/'), '/', -1),
                 '_',
                 1
            ) LIKE CONCAT('%', #{condition.jdKeyword}, '%')
        )


        AND SUBSTRING_INDEX(salary, ' / ', -1) = #{condition.period}



        AND CAST(SUBSTRING_INDEX(salary, ' - ', 1) AS DECIMAL(10,2)) <= #{condition.max_salary}



        AND CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(salary, ' / ', 1), ' - ', -1) AS DECIMAL(10,2)) >= #{condition.min_salary}


        AND create_time >= #{condition.startCreateTime}


        AND create_time <= #{condition.endCreateTime}


        AND update_time >= #{condition.startUpdateTime}


        AND update_time <= #{condition.endUpdateTime}


ORDER BY create_time DESC, update_time DESC
